import json

# Get line numbers for skill invocations
with open('/home/papa/.claude/projects/-home-papa-Documents-ideas-vek-zivi-vek-ucis/9939a30b-953c-411b-8b28-ce648b43fb1e.jsonl') as f:
    lines = f.readlines()

# Find skill invocations
print("=== SKILL INVOCATIONS ===")
for i, line in enumerate(lines):
    try:
        event = json.loads(line)
        if event.get('type') == 'attachment':
            attachment = event.get('attachment', {})
            if attachment.get('type') == 'skill_listing':
                print(f"Line {i+1}: skill_listing attachment, timestamp: {event.get('timestamp')}")
        elif event.get('type') == 'user':
            msg = event.get('message', {})
            content = msg.get('content', '')
            if isinstance(content, str) and '<command-name>/Skill</command-name>' in content:
                print(f"Line {i+1}: Skill tool call (user), timestamp: {event.get('timestamp')}")
    except:
        pass

print(f"\n=== TRANSCRIPT STATS ===")
print(f"Total lines: {len(lines)}")

# Count events by type
types = {}
for line in lines:
    try:
        event = json.loads(line)
        t = event.get('type')
        types[t] = types.get(t, 0) + 1
    except:
        pass

print(f"Event type counts: {types}")

# Check if events are strictly ordered by timestamp
timestamps = []
for line in lines:
    try:
        event = json.loads(line)
        ts = event.get('timestamp')
        if ts:
            timestamps.append(ts)
    except:
        pass

print(f"\nFirst timestamp: {timestamps[0] if timestamps else 'N/A'}")
print(f"Last timestamp: {timestamps[-1] if timestamps else 'N/A'}")
print(f"Events with timestamps: {len(timestamps)}")

# Check ordering
is_ordered = all(timestamps[i] <= timestamps[i+1] for i in range(len(timestamps)-1))
print(f"Strictly ordered by timestamp: {is_ordered}")
