# Collect all field names across user and assistant events
user_fields = set()
assistant_fields = set()

for line in lines:
    try:
        event = json.loads(line)
        if event.get('type') == 'user':
            user_fields.update(event.keys())
        elif event.get('type') == 'assistant':
            assistant_fields.update(event.keys())
    except:
        pass

print("=== USER EVENT FIELDS ===")
for field in sorted(user_fields):
    print(f"  {field}")

print("\n=== ASSISTANT EVENT FIELDS ===")
for field in sorted(assistant_fields):
    print(f"  {field}")

print("\n=== SHARED FIELDS ===")
shared = user_fields & assistant_fields
for field in sorted(shared):
    print(f"  {field}")

